 95→type WorkItemStatus = "pending" | "accepting" | "accepted" | "dismissed";
 96→
 97→async function acceptWorkItem(
 98→  workspaceId: string,
 99→  item: WorkItemSuggestionProps,
100→): Promise<{ entityId: string }> {
101→  const response = await fetch(`/api/workspaces/${workspaceId}/work-items/accept`, {
102→    method: "POST",
103→    headers: { "Content-Type": "application/json" },
104→    body: JSON.stringify({
105→      kind: item.kind,
106→      title: item.title,
107→      rationale: item.rationale,
108→      ...(item.project ? { project: item.project } : {}),
109→      ...(item.priority ? { priority: item.priority } : {}),
110→      ...(item.category ? { category: item.category } : {}),
111→    }),
112→  });
113→  if (!response.ok) {
114→    throw new Error(`accept failed: ${response.status}`);
115→  }
116→  return response.json();
117→}
118→
119→function WorkItemSuggestion(props: WorkItemSuggestionProps) {
120→  const workspaceId = useWorkspaceState((s) => s.workspaceId);
121→  const [status, setStatus] = useState<WorkItemStatus>("pending");
122→
123→  async function handleAccept() {
124→    if (!workspaceId || status !== "pending") {
125→      console.warn("[WorkItemSuggestion] accept skipped", { workspaceId, status });
126→      return;
127→    }
128→    setStatus("accepting");
129→    try {
130→      await acceptWorkItem(workspaceId, props);
131→      setStatus("accepted");
132→    } catch (error) {
133→      console.error("[WorkItemSuggestion] accept failed", error);
134→      setStatus("pending");
135→    }
136→  }
137→
138→  function handleDismiss() {
139→    setStatus("dismissed");
140→  }
141→
142→  if (status === "dismissed") return undefined;
143→
144→  const isDuplicate = props.possibleDuplicateId !== undefined;
145→
146→  return (
147→    <article className={`work-item-suggestion ${status === "accepted" ? "work-item-suggestion--accepted" : ""}`}>
148→      <div className="work-item-suggestion-header">
149→        <div style={{ display: "flex", alignItems: "center", gap: "0.3rem" }}>
150→          <span className="entity-kind">{props.kind === "task" ? "Task" : "Feature"}</span>
151→          {props.category ? <CategoryBadge category={props.category} /> : undefined}
152→          {props.priority ? <span className="work-item-priority">{props.priority}</span> : undefined}
153→        </div>
154→        {status === "accepted" ? (
155→          <span className="work-item-accepted-badge">Accepted</span>
156→        ) : (
157→          <div className="work-item-actions">
158→            <button
159→              type="button"
160→              className="work-item-btn work-item-btn--accept"
161→              onClick={handleAccept}
162→              disabled={status === "accepting"}
163→            >
164→              {status === "accepting" ? "..." : "Accept"}
165→            </button>
166→            <button
167→              type="button"
168→              className="work-item-btn work-item-btn--dismiss"
169→              onClick={handleDismiss}
170→            >
171→              Dismiss
172→            </button>
173→          </div>
174→        )}
175→      </div>
176→      <p className="entity-name">{props.title}</p>
177→      <p className="work-item-rationale">{props.rationale}</p>
178→      {isDuplicate ? (
179→        <p className="work-item-duplicate-hint">
180→          Similar to existing: {props.possibleDuplicateName} ({((props.possibleDuplicateSimilarity ?? 0) * 100).toFixed(0)}% match)
181→        </p>
182→      ) : undefined}
183→      {props.project ? <p className="work-item-project">Project: {props.project}</p> : undefined}
184→    </article>
185→  );
186→}
187→
188→function WorkItemSuggestionList(props: WorkItemSuggestionListProps) {
189→  const workspaceId = useWorkspaceState((s) => s.workspaceId);
190→  const [allStatus, setAllStatus] = useState<"idle" | "accepting">("idle");
191→  const [dismissedAll, setDismissedAll] = useState(false);
192→
193→  async function handleAcceptAll() {
194→    if (!workspaceId || allStatus === "accepting") {
195→      console.warn("[WorkItemSuggestionList] acceptAll skipped", { workspaceId, allStatus });
196→      return;
197→    }
198→    setAllStatus("accepting");
199→    try {
200→      await Promise.all(props.items.map((item) => acceptWorkItem(workspaceId, item)));
201→    } catch (error) {
202→      console.error("[WorkItemSuggestionList] acceptAll failed", error);
203→    }
204→    setAllStatus("idle");
205→  }
206→
207→  function handleDismissAll() {
208→    setDismissedAll(true);
209→  }
210→
211→  if (dismissedAll) return undefined;
212→
213→  return (
214→    <section className="work-item-suggestion-list">
215→      <div className="work-item-suggestion-list-header">
216→        <p className="extraction-summary-title">{props.title}</p>
217→        <div className="work-item-actions">
218→          <button
219→            type="button"
220→            className="work-item-btn work-item-btn--accept"
221→            onClick={handleAcceptAll}
222→            disabled={allStatus === "accepting"}
223→          >
224→            {allStatus === "accepting" ? "Accepting..." : "Accept All"}
225→          </button>
226→          <button
227→            type="button"
228→            className="work-item-btn work-item-btn--dismiss"
229→            onClick={handleDismissAll}
230→          >
231→            Dismiss All
232→          </button>
233→        </div>
234→      </div>
235→      <div className="extraction-summary-grid">
236→        {props.items.map((item) => (
237→          <WorkItemSuggestion key={`${item.kind}:${item.title}`} {...item} />
