143→export const runGraphAwareChat = runChatAgent;
144→
145→type KnownEntity = { entityId: string; kind: string; name: string };
146→
147→/**
148→ * Replace entity name mentions in response text with markdown links:
149→ *   "Model for Extraction Pipeline" → "[Model for Extraction Pipeline](entity://decision:uuid)"
150→ *
151→ * Matches longest names first to avoid partial replacement.
152→ * Only replaces the first occurrence of each entity name.
153→ */
154→function injectEntityLinks(text: string, context: ChatContext): string {
155→  const entities: KnownEntity[] = [];
156→
157→  for (const project of context.workspaceSummary.projects) {
158→    entities.push({ entityId: `project:${project.id}`, kind: "project", name: project.name });
159→  }
160→  for (const decision of context.workspaceSummary.recentDecisions) {
161→    entities.push({ entityId: `decision:${decision.id}`, kind: "decision", name: decision.name });
162→  }
163→  for (const question of context.workspaceSummary.openQuestions) {
164→    entities.push({ entityId: `question:${question.id}`, kind: "question", name: question.name });
165→  }
166→
167→  // Sort longest name first so "Agent-Native Business OS" matches before "Agent"
168→  entities.sort((a, b) => b.name.length - a.name.length);
169→
170→  const replaced = new Set<string>();
171→  let result = text;
172→
173→  for (const entity of entities) {
174→    if (entity.name.length < 3) continue;
175→    if (replaced.has(entity.entityId)) continue;
176→
177→    // Case-insensitive match, but only replace the first occurrence.
178→    // Skip if the name is already inside a markdown link.
179→    const idx = result.toLowerCase().indexOf(entity.name.toLowerCase());
180→    if (idx === -1) continue;
181→
182→    // Check if already inside a markdown link: [...](...)
183→    const before = result.slice(0, idx);
184→    if (before.lastIndexOf("[") > before.lastIndexOf("]")) continue;
185→
186→    const matched = result.slice(idx, idx + entity.name.length);
187→    const link = `[${matched}](#entity/${entity.entityId})`;
188→    result = `${result.slice(0, idx)}${link}${result.slice(idx + entity.name.length)}`;
189→    replaced.add(entity.entityId);
190→  }
191→
192→  return result;
193→}
