 46→export function useChatSession(): UseChatSessionReturn {
 47→  const store = useWorkspaceState();
 48→  const workspaceId = store.workspaceId;
 49→  const workspaceName = store.workspaceName;
 50→  const bootstrapPayload = store.bootstrapPayload;
 51→
 52→  const [sessions, setSessions] = useState<Session[]>([
 53→    {
 54→      id: "main",
 55→      title: "Workspace Chat",
 56→      createdAt: new Date(),
 57→      updatedAt: new Date(),
 58→      conversations: [],
 59→    },
 60→  ]);
 61→  const [activeSessionId] = useState("main");
 62→  const [backendConversationId, setBackendConversationId] = useState<string | undefined>();
 63→  const [activeConversationId, setActiveConversationId] = useState<string | undefined>();
 64→  const [isLoading, setIsLoading] = useState(false);
 65→  const [errorMessage, setErrorMessage] = useState<string | undefined>();
 66→  const [suggestions, setSuggestions] = useState<Suggestion[]>([]);
 67→  const [branchingFromId, setBranchingFromId] = useState<string | undefined>();
 68→  const [inheritedMessageIds, setInheritedMessageIds] = useState<Set<string>>(new Set());
 69→  const [pendingFile, setPendingFile] = useState<File | undefined>();
 70→  const [conversationDiscussEntity, setConversationDiscussEntity] = useState<DiscussEntitySummary | undefined>();
 71→  const streamRef = useRef<EventSource | undefined>(undefined);
 72→  const chatInputRef = useRef<ChatInputRef | null>(null);
 73→
 74→  const discussEntity = useViewState((s) => s.discussEntity);
 75→  const clearDiscussEntity = useViewState((s) => s.clearDiscussEntity);
 76→
 77→  // Track the last applied bootstrap payload to avoid re-applying
 78→  const appliedBootstrapRef = useRef<BootstrapPayload | undefined>(undefined);
 79→
 80→  const activeSession = useMemo(
 81→    () => sessions.find((session) => session.id === activeSessionId),
 82→    [sessions, activeSessionId],
 83→  );
 84→
 85→  if (!activeSession) {
 86→    throw new Error("active session missing");
 87→  }
 88→
 89→  // Apply bootstrap payload when it arrives
 90→  useEffect(() => {
 91→    if (!bootstrapPayload || bootstrapPayload === appliedBootstrapRef.current) {
 92→      return;
 93→    }
 94→    appliedBootstrapRef.current = bootstrapPayload;
 95→
 96→    setSessions([
 97→      {
 98→        id: "main",
 99→        title: workspaceName ?? "Workspace Chat",
100→        createdAt: new Date(),
101→        updatedAt: new Date(),
102→        conversations: bootstrapPayload.conversations,
103→      },
104→    ]);
105→    setInheritedMessageIds(bootstrapPayload.inheritedIds);
106→    setSuggestions(
107→      bootstrapPayload.latestSuggestions.map((content, index) => ({
108→        id: `bootstrap-suggestion-${index}-${content}`,
109→        content,
110→      })),
111→    );
112→    setActiveConversationId(store.conversationId);
113→    setBackendConversationId(store.conversationId);
114→  }, [bootstrapPayload]);
115→
116→  // Highlight message support (graph -> chat navigation)
117→  const highlightMessageId = useViewState((s) => s.highlightMessageId);
118→  const clearHighlight = useViewState((s) => s.clearHighlight);
119→
120→  useEffect(() => {
121→    if (!highlightMessageId) return;
122→
123→    const timer = setTimeout(() => {
124→      const element = document.querySelector(`[data-message-id="${highlightMessageId}"]`);
125→      if (element) {
126→        element.scrollIntoView({ behavior: "smooth", block: "center" });
127→        element.classList.add("animate-highlight");
128→        element.addEventListener(
129→          "animationend",
130→          () => {
131→            element.classList.remove("animate-highlight");
132→          },
133→          { once: true },
134→        );
135→      }
136→      clearHighlight();
137→    }, 100);
138→
139→    return () => clearTimeout(timer);
140→  }, [highlightMessageId, clearHighlight]);
141→
142→  async function refreshSidebar(wsId: string) {
143→    try {
144→      const response = await fetch(`/api/workspaces/${encodeURIComponent(wsId)}/sidebar`);
145→      if (response.ok) {
146→        const payload = await response.json();
147→        store.setSidebar(payload);
148→      }
149→    } catch {
150→      // Sidebar refresh is non-critical; silently ignore
151→    }
152→  }
153→
154→  async function loadConversation(wsId: string, conversationId: string) {
155→    try {
156→      const response = await fetch(
157→        `/api/workspaces/${encodeURIComponent(wsId)}/conversations/${encodeURIComponent(conversationId)}`,
158→      );
159→      if (!response.ok) {
160→        const body = await response.text();
161→        setErrorMessage(body);
162→        return;
163→      }
164→
165→      const payload = (await response.json()) as WorkspaceConversationResponse;
166→      const conversations: Session["conversations"] = [];
167→      let latestSuggestions: string[] = [];
168→      const inheritedIds = new Set<string>();
169→
170→      for (const message of payload.messages) {
171→        if (message.role === "user") {
172→          conversations.push({
173→            id: message.id,
174→            question: message.text,
175→            createdAt: new Date(message.createdAt),
176→          });
177→          if (message.inherited) {
178→            inheritedIds.add(message.id);
179→          }
180→          continue;
181→        }
182→
183→        const last = conversations[conversations.length - 1];
184→        if (last && !last.response) {
185→          last.response = message.text;
186→          last.updatedAt = new Date(message.createdAt);
187→          latestSuggestions =
188→            message.suggestions && message.suggestions.length > 0 ? message.suggestions : [];
189→          if (message.inherited) {
190→            inheritedIds.add(last.id);
191→          }
192→          continue;
193→        }
194→
195→        conversations.push({
196→          id: `assistant-${message.id}`,
197→          question: "",
198→          response: message.text,
199→          createdAt: new Date(message.createdAt),
200→        });

200→        });
201→        if (message.inherited) {
202→          inheritedIds.add(`assistant-${message.id}`);
203→        }
204→        latestSuggestions =
205→          message.suggestions && message.suggestions.length > 0 ? message.suggestions : [];
206→      }
207→
208→      setInheritedMessageIds(inheritedIds);
209→      setSessions([
210→        {
211→          id: "main",
212→          title: workspaceName ?? "Workspace Chat",
213→          createdAt: new Date(),
214→          updatedAt: new Date(),
215→          conversations,
216→        },
217→      ]);
218→
219→      setSuggestions(
220→        latestSuggestions.map((content, index) => ({
221→          id: `conv-suggestion-${index}-${content}`,
222→          content,
223→        })),
224→      );
225→
226→      setActiveConversationId(conversationId);
227→      setBackendConversationId(conversationId);
228→      setConversationDiscussEntity(payload.discussEntity);
229→    } catch (error) {
230→      const messageText = error instanceof Error ? error.message : "Failed to load conversation";
231→      setErrorMessage(messageText);
232→    }
233→  }
234→
235→  function onNewConversation() {
236→    setActiveConversationId(undefined);
237→    setBackendConversationId(undefined);
238→    setSessions([
239→      {
240→        id: "main",
241→        title: workspaceName ?? "Workspace Chat",
242→        createdAt: new Date(),
243→        updatedAt: new Date(),
244→        conversations: [],
245→      },
246→    ]);
247→    setSuggestions([]);
248→    setErrorMessage(undefined);
249→    setConversationDiscussEntity(undefined);
250→    clearDiscussEntity();
251→  }
252→
253→  function onSelectConversation(conversationId: string) {
254→    if (conversationId === activeConversationId || isLoading || !workspaceId) {
255→      return;
256→    }
257→
258→    void loadConversation(workspaceId, conversationId);
259→  }
260→
261→  async function onBranchFromMessage(messageId: string) {
262→    if (!workspaceId || !activeConversationId || isLoading) return;
263→
264→    setBranchingFromId(messageId);
265→    try {
266→      const response = await fetch(
267→        `/api/workspaces/${encodeURIComponent(workspaceId)}/conversations/${encodeURIComponent(activeConversationId)}/branch`,
268→        {
269→          method: "POST",
270→          headers: { "Content-Type": "application/json" },
271→          body: JSON.stringify({ messageId }),
272→        },
273→      );
274→
275→      if (!response.ok) {
276→        const body = await response.text();
277→        setErrorMessage(body);
278→        return;
279→      }
280→
281→      const payload = (await response.json()) as BranchConversationResponse;
282→      await loadConversation(workspaceId, payload.conversationId);
283→      await refreshSidebar(workspaceId);
284→    } catch (error) {
285→      const messageText = error instanceof Error ? error.message : "Branch creation failed";
286→      setErrorMessage(messageText);
287→    } finally {
288→      setBranchingFromId(undefined);
289→    }
290→  }
291→
292→  async function searchMentions(query: string): Promise<MentionItem[]> {
293→    if (!workspaceId) {
294→      return [];
295→    }
296→
297→    const response = await fetch(
298→      `/api/entities/search?q=${encodeURIComponent(query)}&workspaceId=${encodeURIComponent(workspaceId)}&limit=8`,
299→    );
300→    if (!response.ok) {
301→      throw new Error(`entity search failed: ${response.status}`);
302→    }
303→
304→    const rows = (await response.json()) as SearchEntityResponse[];
305→    return rows.map((row) => ({
306→      id: row.id,
307→      label: `${row.kind}: ${row.text.slice(0, 48)}`,
308→      description: `confidence ${row.confidence.toFixed(2)}`,
309→      value: `@${row.id}`,
310→    }));
311→  }
312→
313→  function onUploadFile(file: File) {
314→    setPendingFile(file);
315→  }
316→
317→  function onChatInputClickCapture(event: MouseEvent<HTMLDivElement>) {
318→    if (!pendingFile || isLoading) {
319→      return;
320→    }
321→
322→    const target = event.target;
323→    if (!(target instanceof Element)) {
324→      return;
325→    }
326→
327→    const sendButton = target.closest("button[title='Send']");
328→    if (!sendButton) {
329→      return;
330→    }
331→
332→    const currentMessage = chatInputRef.current?.getValue().trim() ?? "";
333→    if (currentMessage.length > 0) {
334→      return;
335→    }
336→
337→    event.preventDefault();
338→    event.stopPropagation();
339→    void onSendMessage("");
340→  }
341→
342→  async function onSendMessage(
343→    message: string,
344→    options?: { onboardingAction?: OnboardingAction },
345→  ) {
346→    if (isLoading || !workspaceId) {
347→      return;
348→    }
349→
350→    const text = message.trim();
351→    if (!text && !pendingFile) {
352→      return;
353→    }
354→
355→    setErrorMessage(undefined);
356→    setIsLoading(true);
357→    setSuggestions([]);
358→
359→    const clientMessageId = crypto.randomUUID();
360→    const currentAttachment = pendingFile;
361→
362→    setSessions((existing) =>
363→      existing.map((session) =>
364→        session.id === activeSessionId
365→          ? {
366→              ...session,
367→              updatedAt: new Date(),
368→              conversations: [
369→                ...session.conversations,
370→                {
371→                  id: clientMessageId,
372→                  question: text.length > 0 ? text : `Uploaded ${currentAttachment?.name ?? "file"}`,
373→                  createdAt: new Date(),
374→                  ...(currentAttachment
375→                    ? {
376→                        files: [
377→                          {
378→                            name: currentAttachment.name,
379→                            type: currentAttachment.type,
380→                            size: currentAttachment.size,
381→                          },
382→                        ],
383→                      }
384→                    : {}),
385→                },
386→              ],
387→            }
388→          : session,
389→      ),
390→    );
391→
392→    let response: Response;
393→    try {
394→      const includeDiscussEntity = !backendConversationId && discussEntity;
